 18→export interface DewarpConfig {
 19→  xMargin?: number;
 20→  yMargin?: number;
 21→  outputZoom?: number;
 22→  noBinary?: boolean;
 23→}
 24→
 25→function linspace(start: number, end: number, num: number): Array<number> {
 26→  if (num < 2) return num === 1 ? [start] : [];
 27→  const step = (end - start) / (num - 1);
 28→  const arr: Array<number> = [];
 29→  for (let i = 0; i < num; i++) arr.push(start + i * step);
 30→  return arr;
 31→}
 32→
 33→function computeOutputDimensions(
 34→  pageDims: [number, number],
 35→  imgRows: number,
 36→  outputZoom: number
 37→): {
 38→  width: number;
 39→  height: number;
 40→  widthSmall: number;
 41→  heightSmall: number;
 42→} {
 43→  const [pageWidthNorm, pageHeightNorm] = pageDims;
 44→
 45→  let height = 0.5 * pageHeightNorm * outputZoom * imgRows;
 46→  height = roundNearestMultiple(height, Config.REMAP_DECIMATE);
 47→
 48→  let width = roundNearestMultiple(
 49→    (height * pageWidthNorm) / pageHeightNorm,
 50→    Config.REMAP_DECIMATE
 51→  );
 52→
 53→  const MAX_DIM = 3000;
 54→  if (width > MAX_DIM || height > MAX_DIM) {
 55→    const scale = MAX_DIM / Math.max(width, height);
 56→    width = roundNearestMultiple(width * scale, Config.REMAP_DECIMATE);
 57→    height = roundNearestMultiple(height * scale, Config.REMAP_DECIMATE);
 58→    console.log(`  clamping output to ${width}x${height}`);
 59→  }
 60→
 61→  console.log(`  output will be ${width}x${height}`);
 62→
 63→  const heightSmall = Math.floor(height / Config.REMAP_DECIMATE);
 64→  const widthSmall = Math.floor(width / Config.REMAP_DECIMATE);
 65→
 66→  return { width, height, widthSmall, heightSmall };
 67→}
