 69→function buildRemapMaps(
 70→  cv: CV,
 71→  widthSmall: number,
 72→  heightSmall: number,
 73→  pageDims: [number, number],
 74→  params: Array<number>,
 75→  img: CVMat
 76→): { mapX: CVMat; mapY: CVMat; mapXSmall: CVMat; mapYSmall: CVMat } {
