 80→  const pageYRange = linspace(0, pageHeightNorm, heightSmall);
 81→
 82→  const pageXYCoords: Array<[number, number]> = [];
 83→  for (const y of pageYRange) {
 84→    for (const x of pageXRange) {
 85→      pageXYCoords.push([x, y]);
 86→    }
 87→  }
