 92→  const mapXSmall = new cv.Mat();
 93→  mapXSmall.create(heightSmall, widthSmall, cv.CV_32F);
 94→  const mapYSmall = new cv.Mat();
 95→  mapYSmall.create(heightSmall, widthSmall, cv.CV_32F);
 96→
 97→  let invalidPointCount = 0;
