307→function calculatePageExtents(
308→  cv: CV,
309→  small: CVMat,
310→  xMargin: number,
311→  yMargin: number
312→): { pagemask: CVMat; page_outline: Array<[number, number]> } {
313→  const { rows: height, cols: width } = small;
314→  const xmin = xMargin;
315→  const ymin = yMargin;
316→  const xmax = width - xmin;
317→  const ymax = height - ymin;
318→
319→  const pagemask = cv.Mat.zeros(height, width, cv.CV_8UC1);
320→
321→  const pt1 = new cv.Point(xmin, ymin);
322→  const pt2 = new cv.Point(xmax, ymax);
323→  const color = new cv.Scalar(255);
324→  cv.rectangle(pagemask, pt1, pt2, color, -1);
325→
326→  const page_outline: Array<[number, number]> = [
327→    [xmin, ymin],
328→    [xmin, ymax],
329→    [xmax, ymax],
330→    [xmax, ymin],
331→  ];
332→
333→  return { pagemask, page_outline };
334→}
