349→function iterativelyAssembleSpans(
350→  cv: CV,
351→  name: string,
352→  small: CVMat,
353→  pagemask: CVMat,
354→  contour_list: Array<ContourInfo>
355→): Array<Array<ContourInfo>> {
356→  let result = assembleSpans(contour_list);
357→  if (result.spans.length < 3) {
358→    console.log(
359→      `  detecting lines because only ${result.spans.length} text spans`
360→    );
361→    const lineContours = contourInfo(cv, name, small, pagemask, false);
362→    const newResult = attemptReassembleSpans(
363→      name,
364→      small,
365→      pagemask,
366→      lineContours,
367→      result
368→    );
369→    return newResult.spans;
370→  }
371→  return result.spans;
372→}
373→
374→function attemptReassembleSpans(
375→  _name: string,
376→  _small: CVMat,
377→  _pagemask: CVMat,
378→  contour_list: Array<ContourInfo>,
379→  prevResult: { spans: Array<Array<ContourInfo>> }
380→): { spans: Array<Array<ContourInfo>> } {
381→  const newResult = assembleSpans(contour_list);
382→  return newResult.spans.length > prevResult.spans.length
383→    ? newResult
384→    : prevResult;
385→}
