387→async function getPageDims(
388→  cv: CV,
389→  corners: Array<[number, number]>,
390→  roughDims: [number, number],
391→  params: Array<number>
392→): Promise<[number, number]> {
393→  const dst_br = corners[2];
394→
395→  function objective(dimsLocal: Float64Array): number {
396→    const pts: Array<[number, number]> = [[dimsLocal[0], dimsLocal[1]]];
397→    const proj = projectXY(cv, pts, params);
398→    const p = proj[0];
399→    return Math.pow(dst_br[0] - p[0], 2) + Math.pow(dst_br[1] - p[1], 2);
400→  }
401→
402→  const sol = minimize(objective, Array.from(roughDims), {
403→    maxIter: 100,
404→    tol: 1e-6,
405→  });
406→  const newDims: [number, number] = [sol.x[0], sol.x[1]];
407→  console.log(`  got page dims ${newDims[0]} x ${newDims[1]}`);
408→  return newDims;
409→}
