411→async function threshold(
412→  cv: CV,
413→  img: CVMat,
414→  pageDims: [number, number],
415→  params: Array<number>,
416→  outputZoom: number,
417→  noBinary: boolean
418→): Promise<DataUrl> {
419→  const { widthSmall, heightSmall } = computeOutputDimensions(
420→    pageDims,
421→    img.rows,
422→    outputZoom
423→  );
424→
425→  const { mapX, mapY, mapXSmall, mapYSmall } = buildRemapMaps(
426→    cv,
427→    widthSmall,
428→    heightSmall,
429→    pageDims,
430→    params,
431→    img
432→  );
433→
434→  const remapped = applyRemap(cv, img, mapX, mapY);
435→  let result: CVMat;
436→  if (noBinary) {
437→    result = remapped;
438→  } else {
439→    result = applyThreshold(cv, remapped);
440→    remapped.delete();
441→  }
442→
443→  const dataUrl = matToDataUrl(cv, result, "bgr");
444→
445→  mapXSmall.delete();
446→  mapYSmall.delete();
447→  mapX.delete();
448→  mapY.delete();
449→  result.delete();
450→
451→  return dataUrl;
452→}
