  1→import type { CVMat } from "../../types/opencv";
  2→import { Config } from "./config";
  3→import { type ContourInfo } from "./contours";
  4→import { pix2norm } from "./utils";
  5→
  6→/**
  7→ * Computes the absolute angular distance between two angles, normalized to [0, π].
  8→ */
  9→function angleDist(angleB: number, angleA: number): number {
 10→  let diff = angleB - angleA;
 11→  while (diff > Math.PI) diff -= 2 * Math.PI;
 12→  while (diff < -Math.PI) diff += 2 * Math.PI;
 13→  return Math.abs(diff);
 14→}
 15→
 16→interface Edge {
 17→  score: number;
 18→  cinfoA: ContourInfo;
 19→  cinfoB: ContourInfo;
 20→}
 21→
 22→interface SpanStats {
 23→  candidatePairs: number;
 24→  validEdges: number;
 25→  rejectionBreakdown: {
 26→    distance: number;
 27→    overlap: number;
 28→    angle: number;
 29→  };
 30→  linkedContours: number;
 31→  spanSizes: Array<number>;
 32→  spanWidths: Array<number>;
 33→}
 34→
 35→function generateCandidateEdge(
 36→  cinfoA: ContourInfo,
 37→  cinfoB: ContourInfo,
 38→  statsTracker: SpanStats | null
 39→): Edge | null {
 40→  if (cinfoA.point0[0] > cinfoB.point1[0]) {
 41→    [cinfoA, cinfoB] = [cinfoB, cinfoA];
 42→  }
 43→
 44→  const xOverlapA = cinfoA.localOverlap(cinfoB);
 45→  const xOverlapB = cinfoB.localOverlap(cinfoA);
 46→
 47→  const overallTangent = [
 48→    cinfoB.center[0] - cinfoA.center[0],
 49→    cinfoB.center[1] - cinfoA.center[1],
 50→  ];
 51→  const overallAngle = Math.atan2(overallTangent[1], overallTangent[0]);
 52→
 53→  const deltaAngle =
 54→    (Math.max(
 55→      angleDist(cinfoA.angle, overallAngle),
 56→      angleDist(cinfoB.angle, overallAngle)
 57→    ) *
 58→      180) /
 59→    Math.PI;
 60→
 61→  const xOverlap = Math.max(xOverlapA, xOverlapB);
 62→  const dist = Math.sqrt(
 63→    Math.pow(cinfoB.point0[0] - cinfoA.point1[0], 2) +
 64→      Math.pow(cinfoB.point0[1] - cinfoA.point1[1], 2)
 65→  );
 66→
 67→  if (
 68→    dist > Config.EDGE_MAX_LENGTH ||
 69→    xOverlap > Config.EDGE_MAX_OVERLAP ||
 70→    deltaAngle > Config.EDGE_MAX_ANGLE
 71→  ) {
 72→    if (statsTracker) {
 73→      const { rejectionBreakdown } = statsTracker;
 74→      if (dist > Config.EDGE_MAX_LENGTH) {
 75→        rejectionBreakdown.distance++;
 76→      } else if (xOverlap > Config.EDGE_MAX_OVERLAP) {
 77→        rejectionBreakdown.overlap++;
 78→      } else if (deltaAngle > Config.EDGE_MAX_ANGLE) {
 79→        rejectionBreakdown.angle++;
 80→      }
 81→    }
 82→    return null;
 83→  }
 84→
 85→  if (statsTracker) {
 86→    const { validEdges } = statsTracker;
 87→    statsTracker.validEdges = validEdges + 1;
 88→  }
 89→
 90→  const score = dist + deltaAngle * Config.EDGE_ANGLE_COST;
 91→  return { score, cinfoA, cinfoB };
 92→}
 93→
 94→function sortContoursForAssembly(cinfoList: Array<ContourInfo>): void {
 95→  cinfoList.sort(
 96→    (a, b) =>
 97→      a.rect.y - b.rect.y ||
 98→      a.rect.x - b.rect.x ||
 99→      a.rect.width - b.rect.width ||
100→      a.rect.height - b.rect.height
101→  );
102→}
103→
104→function generateAllCandidateEdges(
105→  cinfoList: Array<ContourInfo>,
106→  stats: SpanStats
107→): Array<Edge> {
