282→  let covXY = 0;
283→  let covYY = 0;
284→  for (const p of points) {
285→    const dx = p[0] - meanX;
286→    const dy = p[1] - meanY;
287→    covXX += dx * dx;
288→    covXY += dx * dy;
289→    covYY += dy * dy;
290→  }
291→
292→  const T = covXX + covYY;
293→  const D = covXX * covYY - covXY * covXY;
294→  const L1 = T / 2 + Math.sqrt(Math.max(0, (T * T) / 4 - D));
295→
296→  let vx: number;
297→  let vy: number;
298→  if (Math.abs(covXY) > 1e-9) {
299→    const diff = covXX - L1;
300→    const theta = Math.atan2(-diff, covXY);
301→    vx = Math.cos(theta);
302→    vy = Math.sin(theta);
