320→  x_dir: [number, number];
321→  y_dir: [number, number];
322→  spanAxes: Array<[number, number]>;
323→  spanWeights: Array<number>;
324→  allEvecX: number;
325→  allEvecY: number;
326→  allWeights: number;
327→} {
328→  let allEvecX = 0;
329→  let allEvecY = 0;
330→  let allWeights = 0;
331→
332→  const spanAxes: Array<[number, number]> = [];
333→  const spanWeights: Array<number> = [];
334→
335→  for (const points of spanPoints) {
336→    if (points.length < 2) continue;
337→
338→    const [vx, vy] = getPrincipalAxis(points);
339→    spanAxes.push([vx, vy]);
340→    const pFirst = points[0];
341→    const pLast = points[points.length - 1];
342→
343→    const weight = Math.sqrt(
344→      Math.pow(pLast[0] - pFirst[0], 2) + Math.pow(pLast[1] - pFirst[1], 2)
345→    );
346→    spanWeights.push(weight);
347→
348→    allEvecX += vx * weight;
349→    allEvecY += vy * weight;
350→    allWeights += weight;
351→  }
352→
353→  if (allWeights === 0) {
354→    allEvecX = 1;
355→    allEvecY = 0;
356→    allWeights = 1;
357→  }
358→
359→  const averageAxisX = allEvecX / allWeights;
360→  const averageAxisY = allEvecY / allWeights;
361→
362→  let x_dir: [number, number] = [averageAxisX, averageAxisY];
363→  if (x_dir[0] < 0) x_dir = [-x_dir[0], -x_dir[1]];
364→  const y_dir: [number, number] = [-x_dir[1], x_dir[0]];
365→
366→  return {
367→    x_dir,
368→    y_dir,
369→    spanAxes,
370→    spanWeights,
371→    allEvecX,
372→    allEvecY,
373→    allWeights,
