377→function computePageCorners(
378→  pageCoordsNorm: Array<[number, number]>,
379→  x_dir: [number, number],
380→  y_dir: [number, number]
381→): { corners: Array<[number, number]>; pageXMin: number; pageYMin: number } {
382→  const projectedXCoords = pageCoordsNorm.map(
383→    (p) => p[0] * x_dir[0] + p[1] * x_dir[1]
384→  );
385→  const projectedYCoords = pageCoordsNorm.map(
386→    (p) => p[0] * y_dir[0] + p[1] * y_dir[1]
387→  );
388→
389→  const pageXMin = Math.min(...projectedXCoords);
390→  const pageXMax = Math.max(...projectedXCoords);
391→  const pageYMin = Math.min(...projectedYCoords);
392→  const pageYMax = Math.max(...projectedYCoords);
393→
394→  function getCorner(cx: number, cy: number): [number, number] {
395→    return [cx * x_dir[0] + cy * y_dir[0], cx * x_dir[1] + cy * y_dir[1]];
396→  }
397→
398→  const corners: Array<[number, number]> = [
399→    getCorner(pageXMin, pageYMin),
400→    getCorner(pageXMax, pageYMin),
401→    getCorner(pageXMax, pageYMax),
402→    getCorner(pageXMin, pageYMax),
403→  ];
404→
405→  return { corners, pageXMin, pageYMin };
406→}
