408→function computeSpanCoordinates(
409→  spanPoints: Array<Array<[number, number]>>,
410→  x_dir: [number, number],
411→  y_dir: [number, number],
412→  pageXMin: number,
413→  pageYMin: number
414→): { xcoords: Array<Array<number>>; ycoords: Array<number> } {
415→  const xcoords: Array<Array<number>> = [];
416→  const ycoords: Array<number> = [];
417→
418→  for (const points of spanPoints) {
419→    const px = points.map((p) => p[0] * x_dir[0] + p[1] * x_dir[1]);
420→    const py = points.map((p) => p[0] * y_dir[0] + p[1] * y_dir[1]);
421→
422→    xcoords.push(px.map((v) => v - pageXMin));
423→
424→    const meanY = py.reduce((a, b) => a + b, 0) / py.length;
425→    ycoords.push(meanY - pageYMin);
426→  }
427→
428→  return { xcoords, ycoords };
429→}
