431→/**
432→ * Computes page corners and normalized coordinates for optimization.
433→ */
434→export function keypointsFromSamples(
435→  pagemask: CVMat | { rows: number; cols: number } | [number, number],
436→  page_outline: Array<[number, number]>,
437→  spanPoints: Array<Array<[number, number]>>
438→): {
439→  corners: Array<[number, number]>;
440→  ycoords: Array<number>;
441→  xcoords: Array<Array<number>>;
442→} {
443→  const { x_dir, y_dir } = computeGlobalPageAxes(spanPoints);
444→
445→  const pageCoordsNorm = pix2norm(pagemask, page_outline);
446→  const { corners, pageXMin, pageYMin } = computePageCorners(
447→    pageCoordsNorm,
448→    x_dir,
449→    y_dir
450→  );
451→  const { xcoords, ycoords } = computeSpanCoordinates(
452→    spanPoints,
453→    x_dir,
454→    y_dir,
455→    pageXMin,
456→    pageYMin
457→  );
458→
459→  return { corners, ycoords, xcoords };
460→}
