51→    console.log(`  solvePnP success: ${solution.success}`);
52→    console.log(`  rvec: ${solution.rvec}`);
53→    console.log(`  tvec: ${solution.tvec}`);
54→  }
55→
56→  const refinedParams = [...solution.rvec, ...solution.tvec];
57→
58→  const spanCounts = xcoords.map((xc) => xc.length);
59→
