 25→(function () {
 26→  "use strict";
 27→
 28→  // Override console.log to forward all logs to React Native
 29→  const originalConsoleLog = console.log;
 30→  console.log = function (...args: Array<any>): void {
 31→    // Call original console.log
 32→    originalConsoleLog.apply(console, args);
 33→
 34→    // Forward to React Native
 35→    if (window.ReactNativeWebView) {
 36→      const logMessage = args
 37→        .map((arg) => {
 38→          if (typeof arg === "object") {
 39→            try {
 40→              return JSON.stringify(arg);
 41→            } catch {
 42→              return String(arg);
 43→            }
 44→          }
 45→          return String(arg);
 46→        })
 47→        .join(" ");
 48→
 49→      window.ReactNativeWebView.postMessage(
 50→        JSON.stringify({
 51→          type: "log",
 52→          message: "[OpenCV Bridge] " + logMessage,
 53→        })
 54→      );
 55→    }
 56→  };
 57→
 58→  console.log("Starting OpenCV bridge initialization");
 59→
 60→  let cv: WindowCV | null = null;
 61→  let isReady = false;
 62→
 63→  // Handle OpenCV load error
 64→  window.handleOpenCVLoadError = function (): void {
 65→    console.log("Failed to load opencv.js from CDN");
 66→    if (window.ReactNativeWebView) {
 67→      window.ReactNativeWebView.postMessage(
 68→        JSON.stringify({
 69→          type: "error",
 70→          error: "Failed to load opencv.js from CDN",
 71→        })
 72→      );
 73→    }
 74→  };
 75→
 76→  // Initialize when opencv.js loads
 77→  window.initOpenCV = function (): void {
 78→    console.log("OpenCV script loaded, initializing");
 79→
 80→    // OpenCV.js may not be immediately ready even after script loads
 81→    // We need to wait for cv.onRuntimeInitialized
 82→    if (window.cv && typeof window.cv !== "function") {
 83→      console.log("cv object available, waiting for runtime initialization");
 84→      cv = window.cv;
 85→
 86→      cv["onRuntimeInitialized"] = function (): void {
 87→        try {
 88→          console.log("OpenCV runtime initialized");
 89→
 90→          if (!cv || !cv.Mat) {
 91→            throw new Error("OpenCV Mat not available");
 92→          }
 93→
 94→          // Delete the 'then' method to avoid promise issues
 95→          delete cv.then;
 96→
 97→          isReady = true;
 98→          console.log("OpenCV ready");
 99→
100→          // Notify React Native that we're ready
101→          if (window.ReactNativeWebView) {
102→            window.ReactNativeWebView.postMessage(
103→              JSON.stringify({
104→                type: "ready",
105→              })
106→            );
107→          }
108→        } catch (error) {
109→          const err = error as Error;
110→          console.log("Runtime initialization error: " + err.message);
111→          if (window.ReactNativeWebView) {
112→            window.ReactNativeWebView.postMessage(
113→              JSON.stringify({
114→                type: "error",
115→                error: "OpenCV runtime init failed: " + err.message,
116→              })
117→            );
118→          }
119→        }
120→      };
121→    } else {
122→      console.log("cv not available or is a function");
123→      if (window.ReactNativeWebView) {
124→        window.ReactNativeWebView.postMessage(
125→          JSON.stringify({
126→            type: "error",
127→            error: "OpenCV not available after script load",
128→          })
129→        );
130→      }
131→    }
132→  };
