  1→/**
  2→ * Optimization wrapper for page dewarping.
  3→ * Implements span detection and cubic sheet model fitting.
  4→ *
  5→ * OPTIMIZATION STRATEGY:
  6→ * =====================
  7→ * The dewarping algorithm involves two key optimization problems:
  8→ *
  9→ * 1. SPAN DETECTION (Lines 100-200):
 10→ *    Problem: Find the positions and curvatures of text lines in the image.
 11→ *    Method: Gradient descent to maximize edge density along spans.
 12→ *    Why: We need to know where text lines are to sample keypoints from them.
 13→ *
 14→ * 2. CUBIC SHEET FITTING (Lines 210-280):
 15→ *    Problem: Find the 16 coefficients that best describe the page's 3D shape.
 16→ *    Method: Levenberg-Marquardt (non-linear least squares).
 17→ *    Why: Once we know where keypoints are in the photo, we fit a 3D surface
 18→ *         that, when projected, matches those keypoint positions.
 19→ *
 20→ * The key insight: We're solving an inverse problem. We observe the 2D photo
 21→ * (effect) and want to deduce the 3D page shape (cause). This is inherently
 22→ * an optimization problem because there's no direct formula - we must search
 23→ * for the best-fitting parameters.
 24→ */
 25→
 26→import { levenbergMarquardt } from "ml-levenberg-marquardt";
 27→import type {
 28→  CubicSheetParams,
 29→  DewarpProgressCallback,
 30→  Point2D,
 31→  SpanParams,
 32→} from "../pipelines/geometry/page-dewarp-core";
 33→import {
 34→  createFlatSheetParams,
 35→  evaluateCubicPolynomial,
 36→  project3DTo2D,
 37→  sampleKeypointsOnSpan,
 38→} from "../pipelines/geometry/page-dewarp-core";
 39→
 40→/**
 41→ * Refine span parameters using optimization.
 42→ * Uses simple gradient descent to adjust span positions and curvatures.
 43→ *
 44→ * SPAN REFINEMENT EXPLAINED:
 45→ * =========================
 46→ * We start with rough estimates of where text lines are (from contour detection).
 47→ * Now we refine these estimates to maximize the amount of text contour density
 48→ * that lies along each span.
 49→ *
 50→ * The intuition:
 51→ * - Text contours indicate where text regions are located
 52→ * - A well-positioned span should pass through these text regions
 53→ * - We can measure "contour density" along a span by sampling points
 54→ *
 55→ * The optimization:
 56→ * - Cost function: Lower contour density = higher error
 57→ * - Parameters: yPosition and curvature for each span
 58→ * - Method: Gradient descent (adjust params in direction that reduces error)
 59→ * - Learning rate: How much to adjust params each iteration (0.1 for position)
 60→ *
 61→ * Why gradient descent vs. Levenberg-Marquardt?
 62→ * - This is a simpler problem (fewer parameters: 2 per span vs. 16 total)
 63→ * - The cost function is noisy (contour density isn't perfectly smooth)
 64→ * - Gradient descent is more robust to local minima for this type of problem
 65→ */
 66→export function refineSpans(
 67→  initialSpans: Array<SpanParams>,
 68→  contours: Array<{ x: number; y: number; width: number; height: number }>,
 69→  imageWidth: number,
 70→  imageHeight: number,
 71→  kernelSize: number = 5,
 72→  progressCallback?: DewarpProgressCallback
 73→): {
 74→  spans: Array<SpanParams>;
 75→  iterations: number;
 76→  error: number;
 77→} {
 78→  progressCallback?.("Span Detection", 25, "Computing contour density");
 79→
 80→  const contourDensity = computeContourDensity(
 81→    contours,
 82→    imageWidth,
 83→    imageHeight,
 84→    kernelSize
 85→  );
 86→
 87→  progressCallback?.("Span Detection", 25, "Refining span positions");
 88→
 89→  const numIterations = 50;
 90→  const learningRate = 0.1;
 91→  let currentSpans = initialSpans.map((s) => ({ ...s }));
 92→  let bestError = Infinity;
 93→  let iterations = 0;
 94→
 95→  for (let iter = 0; iter < numIterations; iter++) {
 96→    iterations = iter + 1;
 97→
 98→    const error = evaluateSpanFit(currentSpans, contourDensity, imageWidth);
 99→
100→    if (error < bestError) {
101→      bestError = error;
102→    }
103→
104→    if (iter % 10 === 0) {
105→      const progress = 25 + (iter / numIterations) * 15;
106→      progressCallback?.(
107→        "Span Detection",
108→        progress,
109→        `Iteration ${iter}, error: ${error.toFixed(2)}`
110→      );
111→    }
112→
113→    const gradients = computeSpanGradients(
114→      currentSpans,
115→      contourDensity,
116→      imageWidth
117→    );
118→
119→    for (let i = 0; i < currentSpans.length; i++) {
120→      currentSpans[i].yPosition -= learningRate * gradients[i].yGrad;
121→      currentSpans[i].curvature -= learningRate * gradients[i].cGrad * 0.01;
122→
123→      currentSpans[i].yPosition = Math.max(
124→        10,
125→        Math.min(imageHeight - 10, currentSpans[i].yPosition)
126→      );
127→      currentSpans[i].curvature = Math.max(
128→        -100,
129→        Math.min(100, currentSpans[i].curvature)
130→      );
131→    }
132→  }
133→
134→  progressCallback?.(
135→    "Span Detection",
136→    40,
137→    `Refined ${currentSpans.length} spans in ${iterations} iterations`
138→  );
139→
140→  return {
141→    spans: currentSpans,
142→    iterations,
143→    error: bestError,
144→  };
145→}
146→
147→/**
148→ * Evaluate how well spans match contour density.
149→ *
150→ * This is our cost/error function for span optimization.
151→ * Lower contour density = higher error = worse fit.
152→ *
153→ * Algorithm:
154→ * 1. For each span, sample 20 points along its curve
155→ * 2. Look up the contour density at each sample point
156→ * 3. Sum up the contour density for all points
157→ * 4. Convert to error: error = 1 / (density + 1)
158→ *    (Higher density → lower error)
159→ *
160→ * Why this works:
161→ * - Text regions have high contour density (detected text contours)
162→ * - Background areas have low contour density
163→ * - A span positioned along text will have high total density
164→ * - The optimization will push spans toward text regions
165→ */
166→function evaluateSpanFit(
167→  spans: Array<SpanParams>,
168→  contourDensity: Array<Array<number>>,
169→  imageWidth: number
170→): number {
171→  let totalError = 0;
172→  const numSamples = 20;
173→
174→  for (const span of spans) {
175→    const samples = sampleKeypointsOnSpan(span, imageWidth, numSamples);
176→
177→    let spanDensity = 0;
178→    for (const point of samples) {
179→      const x = Math.floor(point.x);
180→      const y = Math.floor(point.y);
181→
182→      if (
183→        y >= 0 &&
184→        y < contourDensity.length &&
185→        x >= 0 &&
186→        x < contourDensity[0].length
187→      ) {
188→        spanDensity += contourDensity[y][x];
189→      }
190→    }
191→
192→    totalError += 1.0 / (spanDensity + 1);
193→  }
194→
195→  return totalError;
196→}
197→
198→/**
199→ * Compute gradients for span optimization.
200→ *
201→ * NUMERICAL GRADIENT COMPUTATION:
202→ * ==============================
203→ * We need to know: "If I adjust yPosition slightly, does error go up or down?"
204→ *
205→ * Method: Finite differences (numerical differentiation)
206→ * 1. Compute error at current position: error_0
207→ * 2. Nudge parameter by small amount epsilon: param + epsilon
208→ * 3. Compute error at nudged position: error_1
209→ * 4. Gradient = (error_1 - error_0) / epsilon
210→ *
211→ * Positive gradient means: increasing param increases error (bad direction)
212→ * Negative gradient means: increasing param decreases error (good direction)
213→ *
214→ * We compute gradients for both:
215→ * - yGrad: How error changes with vertical position
216→ * - cGrad: How error changes with curvature
217→ *
218→ * Then gradient descent moves against the gradient: param -= learningRate * gradient
219→ */
220→function computeSpanGradients(
221→  spans: Array<SpanParams>,
222→  contourDensity: Array<Array<number>>,
223→  imageWidth: number
224→): Array<{ yGrad: number; cGrad: number }> {
225→  const epsilon = 0.1;
226→  const gradients: Array<{ yGrad: number; cGrad: number }> = [];
227→
228→  for (const span of spans) {
229→    const baseError = evaluateSpanFit([span], contourDensity, imageWidth);
230→
231→    const yPlus = { ...span, yPosition: span.yPosition + epsilon };
232→    const yPlusError = evaluateSpanFit([yPlus], contourDensity, imageWidth);
233→    const yGrad = (yPlusError - baseError) / epsilon;
234→
235→    const cPlus = { ...span, curvature: span.curvature + epsilon };
236→    const cPlusError = evaluateSpanFit([cPlus], contourDensity, imageWidth);
237→    const cGrad = (cPlusError - baseError) / epsilon;
238→
239→    gradients.push({ yGrad, cGrad });
240→  }
241→
242→  return gradients;
243→}
244→
245→/**
246→ * Fit cubic sheet model to keypoints using Levenberg-Marquardt.
247→ *
248→ * THE INVERSE PROBLEM (following Matt Zucker's page_dewarp.py):
249→ * ===========================================================
250→ * Given: Observed keypoint positions in the curved photo
251→ * Find: 3D cubic surface that, when projected, produces those positions
252→ *
253→ * Key insight:
254→ * - Keypoints are sampled from curved text lines (spans) in the photo
255→ * - On a FLAT page, these would be on straight horizontal lines
256→ * - We create a "flat grid" of where keypoints SHOULD be
257→ * - Then find the 3D surface that warps this flat grid → observed positions
258→ *
259→ * Algorithm:
260→ * 1. Create flat page positions (uniform grid)
261→ * 2. For current cubic coefficients:
262→ *    a. Take flat (x, y) position
263→ *    b. Evaluate cubic polynomial: z = f(x, y, coefficients)
264→ *    c. Project 3D point (x, y, z) → 2D position
265→ *    d. Compute error vs. observed position
266→ * 3. LM adjusts coefficients to minimize error
267→ *
268→ * This solves the inverse problem: observed 2D photo → inferred 3D shape
269→ */
270→export function fitCubicSheet(
271→  observedKeypoints: Array<Point2D>,
272→  imageWidth: number,
273→  imageHeight: number,
274→  config: {
275→    maxIterations: number;
276→    tolerance: number;
277→  },
278→  progressCallback?: DewarpProgressCallback
279→): {
280→  params: CubicSheetParams;
281→  iterations: number;
282→  error: number;
283→} {
284→  progressCallback?.("Model Fitting", 40, "Initializing cubic sheet model");
285→
286→  if (observedKeypoints.length === 0) {
287→    console.warn(
288→      "[Dewarp Optimizer] No keypoints provided, using flat page model"
289→    );
290→    progressCallback?.(
291→      "Model Fitting",
292→      70,
293→      "No keypoints, using flat page model"
294→    );
295→    return {
296→      params: createFlatSheetParams(),
297→      iterations: 0,
298→      error: 0,
299→    };
300→  }
301→
302→  const normalizedObserved = observedKeypoints.map((p) => ({
303→    x: (p.x - imageWidth / 2) / imageWidth,
304→    y: (p.y - imageHeight / 2) / imageHeight,
305→  }));
306→
307→  const numKeypoints = observedKeypoints.length;
308→  const minY = Math.min(...normalizedObserved.map((p) => p.y));
309→  const maxY = Math.max(...normalizedObserved.map((p) => p.y));
310→  const yRange = maxY - minY;
311→
312→  const flatPositions = observedKeypoints.map((p, i) => {
313→    const normalizedX = (p.x - imageWidth / 2) / imageWidth;
314→
315→    const rowProgress = i / numKeypoints;
316→    const flatY = minY + rowProgress * yRange;
317→
318→    return { x: normalizedX, y: flatY };
319→  });
320→
321→  const focalLength = Math.max(imageWidth, imageHeight);
322→
323→  const initialParams = createFlatSheetParams();
324→  const x0 = initialParams.coefficients;
325→
326→  progressCallback?.(
327→    "Model Fitting",
328→    45,
329→    `Running Levenberg-Marquardt optimization for ${numKeypoints} keypoints`
330→  );
331→
332→  const fittedParams = [...x0];
333→  let iterations = 0;
334→  let finalError = 0;
335→
336→  const sampleCount = numKeypoints;
337→  const constraintX: Array<number> = [];
338→  const constraintTargets: Array<number> = [];
339→
340→  for (let i = 0; i < sampleCount; i++) {
341→    constraintX.push(i); // Y constraint
342→    constraintTargets.push(normalizedObserved[i].y);
343→
344→    constraintX.push(sampleCount + i); // X constraint (offset)
345→    constraintTargets.push(normalizedObserved[i].x);
346→  }
347→
348→  const evaluateProjection = (
349→    coefficients: Array<number>,
350→    sampleIndex: number
351→  ): { normX: number; normY: number } => {
352→    const flatPos = flatPositions[sampleIndex];
353→
354→    const z = evaluateCubicPolynomial(flatPos.x, flatPos.y, coefficients);
355→
356→    const point3D = {
357→      x: flatPos.x * imageWidth,
358→      y: flatPos.y * imageHeight,
359→      z: z * focalLength,
360→    };
361→
362→    const projected = project3DTo2D(point3D, focalLength, {
363→      x: imageWidth / 2,
364→      y: imageHeight / 2,
365→    });
366→
367→    return {
368→      normX: (projected.x - imageWidth / 2) / imageWidth,
369→      normY: (projected.y - imageHeight / 2) / imageHeight,
370→    };
371→  };
372→
373→  try {
374→    const result = levenbergMarquardt(
375→      { x: constraintX, y: constraintTargets },
376→      (coefficients: Array<number>) => (t: number) => {
377→        const isXConstraint = t >= sampleCount;
378→        const sampleIndex = Math.floor(t % sampleCount);
379→        const projection = evaluateProjection(coefficients, sampleIndex);
380→
381→        return isXConstraint ? projection.normX : projection.normY;
382→      },
383→      {
384→        initialValues: x0,
385→        maxIterations: config.maxIterations,
386→        errorTolerance: config.tolerance,
387→      }
388→    );
389→
390→    fittedParams.splice(0, fittedParams.length, ...result.parameterValues);
391→    iterations = result.iterations;
392→    finalError = result.parameterError;
393→
394→    progressCallback?.(
395→      "Model Fitting",
396→      70,
397→      `Fitted model in ${iterations} iterations, error: ${finalError.toFixed(
398→        4
399→      )}`
400→    );
401→  } catch (error) {
402→    console.warn(
403→      "[Dewarp Optimizer] Levenberg-Marquardt failed, using initial parameters:",
404→      error
405→    );
406→
407→    progressCallback?.(
408→      "Model Fitting",
409→      70,
410→      "Optimization failed, using flat page model"
411→    );
412→  }
413→
414→  return {
415→    params: { coefficients: fittedParams },
416→    iterations,
417→    error: finalError,
418→  };
419→}
420→
421→/**
422→ * Compute edge density map for span optimization.
423→ *
424→ * EDGE DENSITY EXPLAINED:
425→ * ======================
426→ * The edge map from Canny detection is binary: each pixel is either an edge (255)
427→ * or not an edge (0). This is too noisy to optimize with directly.
428→ *
429→ * We create a smoothed "edge density" map:
430→ * - For each pixel, look at a small neighborhood (kernelSize × kernelSize)
431→ * - Average the edge values in that neighborhood
432→ * - Store the average as the "density" at that pixel
433→ *
434→ * Why this helps:
435→ * - Text regions have many edges close together → high density
436→ * - Background regions have few edges → low density
437→ * - The smoothed density is continuous, making optimization easier
