  1→/**
  2→ * Span estimation for page dewarping.
  3→ */
  4→
  5→import type { OpenCVPreprocessing } from "@/lib/photo-processor/opencv";
  6→import type { DataUrl } from "@/lib/types/primitives";
  7→import type { Mat } from "@techstark/opencv-js";
  8→import type { Point2D, SpanParams } from "../page-dewarp-core";
  9→
 10→/**
 11→ * Extract initial span estimates from detected lines.
 12→ *
 13→ * INITIAL SPAN ESTIMATION:
 14→ * =======================
 15→ * From the lines detected by Hough transform, we need to extract rough
 16→ * positions for horizontal text spans.
 17→ *
 18→ * Algorithm:
 19→ * 1. Filter to approximately horizontal lines (angle < 30°)
 20→ * 2. Sort lines by vertical position (top to bottom)
 21→ * 3. Divide the page into numSpans regions
 22→ * 4. For each region, find the closest detected line
 23→ * 5. Use that line's position as the initial span estimate
 24→ *
 25→ * Why this approach?
 26→ * - Hough lines give us real detected features (not just guesses)
 27→ * - Horizontal filtering ensures we're looking at text, not page edges
 28→ * - Even spacing ensures we sample across the whole page
 29→ * - These estimates will be refined by optimization later
 30→ *
 31→ * Fallback: If no lines detected in a region, we use evenly-spaced positions.
 32→ * This ensures we always have span estimates to work with.
 33→ */
 34→export function extractSpanEstimates(
 35→  lines: Array<{ start: Point2D; end: Point2D }>,
 36→  imageHeight: number,
 37→  numSpans: number
 38→): Array<SpanParams> {
 39→  const horizontalLines = lines.filter((line) => {
 40→    const angle = Math.abs(
 41→      Math.atan2(line.end.y - line.start.y, line.end.x - line.start.x)
 42→    );
 43→    return angle < Math.PI / 6 || angle > (5 * Math.PI) / 6;
 44→  });
 45→
 46→  horizontalLines.sort((a, b) => {
 47→    const yA = (a.start.y + a.end.y) / 2;
 48→    const yB = (b.start.y + b.end.y) / 2;
 49→    return yA - yB;
 50→  });
 51→
 52→  const spans: Array<SpanParams> = [];
 53→  const step = imageHeight / (numSpans + 1);
 54→
 55→  for (let i = 0; i < numSpans; i++) {
 56→    const targetY = step * (i + 1);
 57→
 58→    let closestLine = horizontalLines.find((line) => {
 59→      const lineY = (line.start.y + line.end.y) / 2;
 60→      return Math.abs(lineY - targetY) < step / 2;
 61→    });
 62→
 63→    if (!closestLine && horizontalLines.length > 0) {
 64→      closestLine = horizontalLines[Math.min(i, horizontalLines.length - 1)];
 65→    }
 66→
 67→    const yPosition = closestLine
 68→      ? (closestLine.start.y + closestLine.end.y) / 2
 69→      : targetY;
 70→
 71→    spans.push({
 72→      yPosition,
 73→      curvature: 0,
 74→    });
 75→  }
 76→
 77→  return spans;
 78→}
 79→
 80→/**
 81→ * Extract span estimates from text contours.
 82→ * Groups contours by vertical position to find text lines.
 83→ */
 84→export function extractSpanEstimatesFromContours(
 85→  textContours: Array<{
 86→    rect: { x: number; y: number; width: number; height: number };
 87→  }>,
 88→  imageHeight: number,
 89→  numSpans: number
 90→): Array<SpanParams> {
 91→  if (textContours.length === 0) {
 92→    return extractSpanEstimates([], imageHeight, numSpans);
 93→  }
 94→
 95→  const availableY = textContours
 96→    .map((tc) => tc.rect.y + tc.rect.height / 2)
 97→    .sort((a, b) => a - b);
 98→
 99→  const spans: Array<SpanParams> = [];
100→  const step = imageHeight / (numSpans + 1);
