  1→/**
  2→ * Core mathematical utilities for page dewarping.
  3→ * Implements cubic polynomial evaluation, 3D projection, and span parameterization.
  4→ *
  5→ * ALGORITHM OVERVIEW:
  6→ * ==================
  7→ * The page dewarping algorithm models a curved page as a 3D surface in space,
  8→ * then determines how that surface projects onto the camera's 2D image plane.
  9→ *
 10→ * Key concepts:
 11→ * 1. CUBIC SHEET MODEL: The page is represented as a cubic polynomial surface
 12→ *    z(x, y) = sum of c_ij * x^i * y^j for i,j = 0..3
 13→ *    This gives us 16 coefficients that describe the page's curvature.
 14→ *
 15→ * 2. TEXT SPANS: Horizontal lines of text that follow the page's curvature.
 16→ *    We detect these spans and sample keypoints along them.
 17→ *
 18→ * 3. PROJECTION: Each point on the 3D curved surface projects to a specific
 19→ *    location in the 2D photograph. We model this with perspective projection.
 20→ *
 21→ * 4. INVERSE MAPPING: Once we know the surface shape, we can map any point
 22→ *    on a flat output image back to where it came from in the curved input,
 23→ *    effectively "unwarping" the page.
 24→ */
 25→
 26→/**
 27→ * Progress callback for reporting algorithm status.
 28→ */
 29→export type DewarpProgressCallback = (
 30→  phase: string,
 31→  progress: number,
 32→  message: string
 33→) => void;
 34→
 35→/**
 36→ * 2D point in image coordinates.
 37→ */
 38→export interface Point2D {
 39→  x: number;
 40→  y: number;
 41→}
 42→
 43→/**
 44→ * 3D point in world coordinates.
 45→ */
 46→export interface Point3D {
 47→  x: number;
 48→  y: number;
 49→  z: number;
 50→}
 51→
 52→/**
 53→ * Cubic polynomial coefficients (16 parameters for cubic sheet).
 54→ */
 55→export interface CubicSheetParams {
 56→  coefficients: Array<number>;
 57→}
 58→
 59→/**
 60→ * Span line parameters (position and curvature).
 61→ */
 62→export interface SpanParams {
 63→  yPosition: number;
 64→  curvature: number;
 65→}
 66→
 67→/**
 68→ * Evaluate a cubic polynomial at a given point.
 69→ * z(x, y) = Σ(i=0..3) Σ(j=0..3) c_ij * x^i * y^j
 70→ *
 71→ * This is the heart of the cubic sheet model. The function takes a 2D point
 72→ * on the page (x, y) and computes its height (z) above the flat plane.
 73→ *
 74→ * For a flat page, all coefficients would be zero except c_00.
 75→ * For a curved page (like an open book), the coefficients capture:
 76→ * - Linear terms (x, y): overall tilt
 77→ * - Quadratic terms (x², xy, y²): cylindrical curves (like book binding)
 78→ * - Cubic terms (x³, x²y, xy², y³): more complex warping
 79→ *
 80→ * The 16 coefficients are arranged as:
 81→ * [c_00, c_01, c_02, c_03,  // constant, y, y², y³
 82→ *  c_10, c_11, c_12, c_13,  // x, xy, xy², xy³
 83→ *  c_20, c_21, c_22, c_23,  // x², x²y, x²y², x²y³
 84→ *  c_30, c_31, c_32, c_33]  // x³, x³y, x³y², x³y³
 85→ */
 86→export function evaluateCubicPolynomial(
 87→  x: number,
 88→  y: number,
 89→  coefficients: Array<number>
 90→): number {
 91→  if (coefficients.length !== 16) {
 92→    throw new Error("Cubic polynomial requires exactly 16 coefficients");
 93→  }
 94→
 95→  let z = 0;
 96→  let index = 0;
 97→
 98→  for (let i = 0; i <= 3; i++) {
 99→    for (let j = 0; j <= 3; j++) {
100→      const term = coefficients[index] * Math.pow(x, i) * Math.pow(y, j);
101→      z += term;
102→      index++;
103→    }
104→  }
105→
106→  return z;
107→}
108→
109→/**
110→ * Compute the gradient of the cubic polynomial at a point.
111→ * Returns [dz/dx, dz/dy].
112→ *
113→ * The gradient tells us how steeply the surface is sloping in each direction.
114→ * This is useful for:
115→ * - Optimization (finding the direction to adjust parameters)
116→ * - Visualizing the surface curvature
117→ * - Understanding how the page bends at each location
118→ *
119→ * We compute partial derivatives:
120→ * dz/dx = Σ(i=1..3) Σ(j=0..3) c_ij * i * x^(i-1) * y^j
121→ * dz/dy = Σ(i=0..3) Σ(j=1..3) c_ij * j * x^i * y^(j-1)
122→ */
123→export function cubicPolynomialGradient(
124→  x: number,
125→  y: number,
126→  coefficients: Array<number>
127→): [number, number] {
128→  if (coefficients.length !== 16) {
129→    throw new Error("Cubic polynomial requires exactly 16 coefficients");
130→  }
131→
132→  let dzDx = 0;
133→  let dzDy = 0;
134→  let index = 0;
135→
136→  for (let i = 0; i <= 3; i++) {
137→    for (let j = 0; j <= 3; j++) {
138→      const coef = coefficients[index];
139→
140→      if (i > 0) {
141→        dzDx += coef * i * Math.pow(x, i - 1) * Math.pow(y, j);
142→      }
143→
144→      if (j > 0) {
145→        dzDy += coef * j * Math.pow(x, i) * Math.pow(y, j - 1);
146→      }
147→
148→      index++;
149→    }
150→  }
151→
152→  return [dzDx, dzDy];
153→}
154→
155→/**
156→ * Project a 3D point to 2D image coordinates using a simple perspective model.
157→ * Assumes camera at origin looking down the z-axis.
158→ *
159→ * PERSPECTIVE PROJECTION EXPLAINED:
160→ * =================================
161→ * When a camera photographs a 3D object, points closer to the camera appear
162→ * larger than points farther away. This is perspective distortion.
163→ *
164→ * Our model:
165→ * - Camera is at position (0, 0, 0) looking down the +z axis
166→ * - The page is in front of the camera (positive z)
167→ * - Focal length determines the camera's "zoom" (larger = more zoomed in)
168→ *
169→ * The projection formula:
170→ * - Points farther from camera (larger z) appear smaller
171→ * - scale = focalLength / (focalLength + z)
172→ * - x_2d = x_3d * scale + center_x
173→ * - y_2d = y_3d * scale + center_y
174→ *
175→ * For a curved page, points that bulge toward the camera (positive z) will
176→ * appear larger/displaced in the photo compared to flat regions.
177→ */
178→export function project3DTo2D(
179→  point3D: Point3D,
180→  focalLength: number = 1000,
181→  imageCenter: Point2D = { x: 0, y: 0 }
182→): Point2D {
