  1→/**
  2→ * Remapping logic for page dewarping.
  3→ * Generates mesh grid and applies inverse transformation.
  4→ *
  5→ * REMAPPING PHASE EXPLAINED:
  6→ * =========================
  7→ * Now that we know the 3D shape of the page (from cubic sheet fitting),
  8→ * we need to actually dewarp the image - create a flat output from the
  9→ * curved input.
 10→ *
 11→ * The challenge: Forward vs. Inverse mapping
 12→ * - Forward: "Where does this input pixel go in the output?" → Leaves holes
 13→ * - Inverse: "Where did this output pixel come from in the input?" → Perfect
 14→ *
 15→ * We use inverse mapping:
 16→ * 1. For each pixel (x, y) in the flat output image:
 17→ *    a. Treat it as a point on the flat page
 18→ *    b. Use the cubic model to determine its z-height on the 3D surface
 19→ *    c. Project that 3D point to find where it appears in the input photo
 20→ * 2. Sample the input photo at that location (with interpolation)
 21→ * 3. Copy the color to the output pixel
 22→ *
 23→ * OpenCV's remap() function:
 24→ * - Takes two "map" images: mapX and mapY
 25→ * - For each output pixel at (x, y):
 26→ *   - Looks up source_x = mapX[y][x] and source_y = mapY[y][x]
 27→ *   - Samples input image at (source_x, source_y)
 28→ *   - Uses cubic interpolation for smooth results
 29→ *
 30→ * Result: A flat, dewarped image where text lines are horizontal.
 31→ */
 32→
 33→import type { DataUrl } from "@/lib/types/primitives";
 34→import type { Mat } from "@techstark/opencv-js";
 35→import type {
 36→  CubicSheetParams,
 37→  DewarpProgressCallback,
 38→  Point2D,
 39→  Point3D,
 40→} from "./page-dewarp-core";
 41→import { evaluateCubicPolynomial, project3DTo2D } from "./page-dewarp-core";
 42→
 43→/**
 44→ * OpenCV Size type.
 45→ */
 46→export interface CVSize {
 47→  width: number;
 48→  height: number;
 49→}
 50→
 51→/**
 52→ * OpenCV Scalar type for color values.
 53→ */
 54→export interface CVScalar {
 55→  readonly length: number;
 56→}
 57→
 58→/**
 59→ * OpenCV MatVector type for collections of Mat objects.
 60→ */
 61→export interface CVMatVector {
 62→  push_back: (mat: Mat) => void;
 63→  delete: () => void;
 64→  size: () => number;
 65→  get: (index: number) => Mat;
 66→}
 67→
 68→/**
 69→ * OpenCV interface for remapping operations.
 70→ */
 71→export interface OpenCVRemap {
 72→  Mat: new (rows?: number, cols?: number, type?: number) => Mat;
 73→  MatVector: new () => CVMatVector;
 74→  remap: (
 75→    src: Mat,
 76→    dst: Mat,
 77→    map1: Mat,
 78→    map2: Mat,
 79→    interpolation: number,
 80→    borderMode?: number,
 81→    borderValue?: CVScalar
 82→  ) => void;
 83→  convertScaleAbs: (src: Mat, dst: Mat, alpha?: number, beta?: number) => void;
 84→  adaptiveThreshold: (
 85→    src: Mat,
 86→    dst: Mat,
 87→    maxValue: number,
 88→    adaptiveMethod: number,
 89→    thresholdType: number,
 90→    blockSize: number,
 91→    C: number
 92→  ) => void;
 93→  cvtColor: (src: Mat, dst: Mat, code: number) => void;
 94→  resize: (
 95→    src: Mat,
 96→    dst: Mat,
 97→    dsize: CVSize,
 98→    fx?: number,
 99→    fy?: number,
100→    interpolation?: number
101→  ) => void;
102→  hconcat: (src: CVMatVector, dst: Mat) => void;
103→  line: (
104→    img: Mat,
105→    pt1: Point2D,
106→    pt2: Point2D,
107→    color: CVScalar,
108→    thickness?: number
109→  ) => void;
110→  circle: (
111→    img: Mat,
112→    center: Point2D,
113→    radius: number,
114→    color: CVScalar,
115→    thickness?: number
116→  ) => void;
117→  imshow: (canvas: HTMLCanvasElement, mat: Mat) => void;
118→  CV_32FC1: number;
119→  INTER_CUBIC: number;
120→  INTER_LINEAR: number;
121→  BORDER_CONSTANT: number;
122→  ADAPTIVE_THRESH_GAUSSIAN_C: number;
123→  THRESH_BINARY: number;
124→  THRESH_BINARY_INV: number;
125→  COLOR_RGBA2GRAY: number;
126→  COLOR_GRAY2RGBA: number;
127→  Size: new (width: number, height: number) => CVSize;
128→  Scalar: new (...values: Array<number>) => CVScalar;
129→}
130→
131→/**
132→ * Generate dewarp transformation maps.
133→ *
134→ * MAP GENERATION EXPLAINED:
135→ * ========================
136→ * This is where we compute the inverse mapping from flat output to curved input.
137→ *
138→ * For each pixel in the output image:
139→ * 1. Normalize coordinates: (x, y) → (normX, normY) in range [-0.5, 0.5]
140→ *    - This makes the math scale-independent
141→ *
142→ * 2. Evaluate cubic polynomial: z = f(normX, normY)
143→ *    - Get the height of the page at this location
144→ *    - z = 0 means flat, z > 0 means bulging toward camera
145→ *
146→ * 3. Create 3D point: (normX * width, normY * height, z * width)
147→ *    - Scale back to image coordinates
148→ *    - z is scaled by width to keep proportions reasonable
149→ *
150→ * 4. Project to 2D: (x_input, y_input) = project3D(point3D)
151→ *    - This tells us where this flat point appears in the curved photo
152→ *
153→ * 5. Store in maps: mapX[y][x] = x_input, mapY[y][x] = y_input
154→ *
155→ * Why two separate maps?
156→ * - OpenCV remap() wants separate X and Y coordinate maps
157→ * - This format allows for arbitrary transformations (not just our dewarping)
158→ *
159→ * The maps are CV_32FC1 (32-bit float, single channel) to allow sub-pixel accuracy.
160→ */
161→export function generateDewarpMaps(
162→  cv: OpenCVRemap,
163→  sheetParams: CubicSheetParams,
164→  sourceWidth: number,
165→  sourceHeight: number,
166→  outputWidth: number,
167→  outputHeight: number,
168→  progressCallback?: DewarpProgressCallback
169→): { mapX: Mat; mapY: Mat } {
170→  if (progressCallback) {
171→    progressCallback("Remapping", 70, "Generating transformation maps");
172→  }
173→
174→  const mapX = new cv.Mat(outputHeight, outputWidth, cv.CV_32FC1);
175→  const mapY = new cv.Mat(outputHeight, outputWidth, cv.CV_32FC1);
176→
177→  const focalLength = Math.max(sourceWidth, sourceHeight);
178→
179→  for (let y = 0; y < outputHeight; y++) {
180→    for (let x = 0; x < outputWidth; x++) {
181→      const normX = (x - outputWidth / 2) / outputWidth;
182→      const normY = (y - outputHeight / 2) / outputHeight;
183→
184→      const z = evaluateCubicPolynomial(normX, normY, sheetParams.coefficients);
185→
186→      // When z is 0 (flat page), this should be a simple coordinate mapping
187→      if (Math.abs(z) < 1e-10) {
188→        // Direct mapping from output to source coordinates
189→        const sourceX = (x / outputWidth) * sourceWidth;
190→        const sourceY = (y / outputHeight) * sourceHeight;
191→
192→        const idx = y * outputWidth + x;
193→        mapX.data32F[idx] = sourceX;
194→        mapY.data32F[idx] = sourceY;
195→      } else {
196→        // Apply perspective projection for curved pages
197→        const point3D: Point3D = {
198→          x: normX * sourceWidth,
199→          y: normY * sourceHeight,
200→          z: z * sourceWidth,
201→        };
202→
203→        const projected = project3DTo2D(point3D, focalLength, {
204→          x: sourceWidth / 2,
205→          y: sourceHeight / 2,
206→        });
207→
208→        const idx = y * outputWidth + x;
209→        mapX.data32F[idx] = projected.x;
210→        mapY.data32F[idx] = projected.y;
211→      }
212→    }
213→
214→    if (y % 50 === 0 && progressCallback) {
215→      const progress = 70 + (y / outputHeight) * 15;
216→      progressCallback(
217→        "Remapping",
218→        progress,
219→        `Generating maps: ${Math.floor((y / outputHeight) * 100)}%`
220→      );
221→    }
222→  }
223→
224→  if (progressCallback) {
225→    progressCallback("Remapping", 85, "Transformation maps generated");
226→  }
227→
228→  return { mapX, mapY };
229→}
230→
